// Extract and validate query params
// Expected: clinic_id, gclid?, fbclid?, utm_source?, utm_medium?, utm_campaign?, utm_content?, utm_term?, landing_page?

const qs = $input.first().json.query || {};
const body = $input.first().json.body || {};

// Params can arrive as query string or body
const p = { ...qs, ...body };

const clinicId = p.clinic_id || null;
const gclid = p.gclid || null;
const fbclid = p.fbclid || null;
const utmSource = p.utm_source || null;
const utmMedium = p.utm_medium || null;
const utmCampaign = p.utm_campaign || null;
const utmContent = p.utm_content || null;
const utmTerm = p.utm_term || null;
const landingPage = p.landing_page || null;

if (!clinicId) {
  return [{ json: { valid: false, error: 'clinic_id is required' } }];
}

return [{
  json: {
    valid: true,
    clinicId,
    gclid,
    fbclid,
    utmSource,
    utmMedium,
    utmCampaign,
    utmContent,
    utmTerm,
    landingPage
  }
}];

// Check if dedup query returned an existing active click
const rows = $input.all();
const params = $('Extrair Params').first().json;

if (rows.length > 0 && rows[0].json?.id) {
  const existing = rows[0].json;
  return [{
    json: {
      ...params,
      hasExisting: true,
      existingId: existing.id,
      existingRefCode: existing.ref_code,
      existingExpiresAt: existing.expires_at
    }
  }];
}

// No existing click — generate 3 candidate ref codes [A-Z0-9]
const CHARS = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
const genCode = () => Array.from({ length: 3 }, () => CHARS[Math.floor(Math.random() * CHARS.length)]).join('');

return [{
  json: {
    ...params,
    hasExisting: false,
    candidates: [genCode(), genCode(), genCode()]  // 3 tries on conflict
  }
}];

// Merge result from insert attempt 1 with original params
const insertRows = $input.all();
const params = $('Avaliar Dedup').first().json;

if (insertRows.length > 0 && insertRows[0].json?.id) {
  const row = insertRows[0].json;
  return [{ json: { success: true, id: row.id, ref_code: row.ref_code, expires_at: row.expires_at, ...params } }];
}

// Collision on candidate[0] — try candidate[1]
return [{ json: { success: false, ...params } }];

// Merge result from insert attempt 2 with params
const insertRows = $input.all();
const params = $('Avaliar Tentativa 1').first().json;

if (insertRows.length > 0 && insertRows[0].json?.id) {
  const row = insertRows[0].json;
  return [{ json: { success: true, id: row.id, ref_code: row.ref_code, expires_at: row.expires_at, ...params } }];
}

// Still collision — try candidate[2]
return [{ json: { success: false, ...params } }];

// Final merge — use whatever row was returned (or fail)
const insertRows = $input.all();

if (insertRows.length > 0 && insertRows[0].json?.id) {
  const row = insertRows[0].json;
  return [{ json: { success: true, id: row.id, ref_code: row.ref_code, expires_at: row.expires_at } }];
}

// All 3 candidates collided (extremely unlikely)
return [{ json: { success: false } }];
